                console.log(`[expander-debug] rong: seat=${l} p=${p} cleanP=${p.slice(0,2)} expanders=${expanders.length} expanderCandidates=${expanders.map(e => e.candidates.join(',')).join('|')}`);
                let cleanP = p.slice(0, 2);
